@module modalHost  src=modalHost.lua  loc=140  sha=6362c91  mode=chunk
@deps ctx, chrome

# Invariants & contracts
  @invariant  one modalHost per coordinator; threaded into every page that opens modals
  @invariant  state.kind picks the render; built-ins are 'prompt' and 'confirm'; pages register custom kinds at load time

# Shapes
  @shape  state = { kind, title, callback?, onClose?, flags?, ... per-kind fields }

# Imports
  @require ImGui = 'imgui'  @ 7
      @contract  render(state, close) draws inside an active BeginPopupModal; close(invoke, ...args) captures+clears state, closes popup, pcalls callback if invoke, then pcalls onClose unconditionally

# Private state
  @state POPUP_ID = '###modalHost'  @ 12
  @state kinds = {}  @ 14
  @state state = nil  @ 15
  @state wasOpen = false  @ 16   -- snapshot at tick(); stays true across the closing frame
  @state mh = {}  @ 20

# Private functions
  @fn label()  @ 18

# Public API (mh:*)
  @api mh:registerKind(kind, render)  @ 22
  @api mh:open(s)  @ 24
  @api mh:openPrompt(args)  @ 29
  @api mh:openConfirm(args)  @ 41
  @api mh:isOpen()  @ 50
  @api mh:wasOpenAtFrameStart()  @ 51
  @api mh:tick()  @ 53
  @api mh:draw()  @ 55

# Uses (outbound edges)
  @use call    chrome.popChromeWindow  @ 90
  @use call    chrome.pushChromeWindow  @ 65
  @use call    imgui.BeginPopupModal  @ 67
  @use call    imgui.CloseCurrentPopup  @ 74
  @use call    imgui.EndPopup  @ 86
  @use call    imgui.GetWindowViewport  @ 62
  @use call    imgui.InputText  @ 117, 128
  @use call    imgui.IsKeyPressed  @ 97, 99, 121, 122, 124, 132
  @use call    imgui.IsPopupOpen  @ 59
  @use call    imgui.IsWindowAppearing  @ 105
  @use call    imgui.OpenPopup  @ 26, 60
  @use call    imgui.SetKeyboardFocusHere  @ 106
  @use call    imgui.SetNextWindowPos  @ 63
  @use call    imgui.Text  @ 96, 107, 120
  @use call    imgui.Viewport_GetCenter  @ 62
  @use require imgui  @ 7

# REAPER API surface
  @reaper ShowConsoleMsg
